const item = $input.first().json;
const body = item.body || item;
const rawHeaders = item.headers || {};
const headers = Object.fromEntries(
  Object.entries(rawHeaders).map(([k, v]) => [k.toLowerCase(), v])
);

const authToken = $env.WEBHOOK_AUTH_TOKEN;
if (authToken && headers['x-webhook-token'] !== authToken) {
  return [{ json: { valid: false, error: 'Unauthorized: invalid webhook token', statusCode: 401 } }];
}

const customer_email = body.customer_email || body.email;
const message = body.message || body.inquiry;

if (!customer_email || !message) {
  return [{ json: { valid: false, error: 'Missing required fields: customer_email and message', statusCode: 400 } }];
}

return [{
  json: {
    valid: true,
    customer_name: body.customer_name || body.name || 'Customer',
    customer_email,
    subject: body.subject || 'Support Inquiry',
    message,
    received_at: new Date().toISOString(),
    _startedAt: Date.now()
  }
}];

