=Classify this customer support inquiry into exactly ONE intent.

Reply with ONLY valid JSON (no markdown fences):
{"intent":"billing|technical|feature_request|unknown","confidence":0.95,"reason":"brief reason"}

Subject: {{ $json.subject }}
Message: {{ $json.message }}

parameters.jsCode:
const normalized = $('Normalize Input').first().json;
const llmItem = $input.first().json;
const llmOutput = llmItem.text || llmItem.output || llmItem.response || JSON.stringify(llmItem);

let parsed = { intent: 'unknown', confidence: 0.5, reason: 'default' };
try {
  const cleaned = String(llmOutput).replace(/```json\n?/gi, '').replace(/```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) parsed = JSON.parse(match[0]);
} catch (e) {
  const msg = (normalized.message || '').toLowerCase();
  if (/charge|bill|refund|invoice|payment/.test(msg)) parsed.intent = 'billing';
  else if (/api|401|login|sso|webhook|deploy|error/.test(msg)) parsed.intent = 'technical';
  else if (/feature|slack|integration|roadmap|request/.test(msg)) parsed.intent = 'feature_request';
  parsed.reason = 'keyword_fallback';
}

const validIntents = ['billing', 'technical', 'feature_request', 'unknown'];
if (!validIntents.includes(parsed.intent)) parsed.intent = 'unknown';

const confidence = Number(parsed.confidence) || 0.5;
const threshold = Number($env.INTENT_CONFIDENCE_THRESHOLD || 0.55);
if (confidence < threshold && parsed.intent !== 'unknown') {
  parsed.intent = 'unknown';
  parsed.reason = `low_confidence_${confidence.toFixed(2)}`;
}

return [{
  json: {
    ...normalized,
    intent: parsed.intent,
    intent_confidence: confidence,
    intent_reason: parsed.reason || '',
    _startedAt: normalized._startedAt
  }
}];

