const routeData = $('Parse Intent').first().json;
const agentItem = $input.first().json;
const response_body = agentItem.output || agentItem.text || agentItem.response || JSON.stringify(agentItem);

let rag_sources = [];
try {
  if (agentItem.sourceDocuments) rag_sources = agentItem.sourceDocuments;
  else if (agentItem.intermediateSteps) {
    rag_sources = agentItem.intermediateSteps
      .filter(s => s.action?.tool)
      .map(s => ({ tool: s.action.tool, observation: String(s.observation || '').slice(0, 500) }));
  }
} catch (e) {}

return [{
  json: {
    ...routeData,
    response_body: typeof response_body === 'string' ? response_body : JSON.stringify(response_body),
    rag_sources
  }
}];

