const item = $input.first().json;
const startedAt = item._startedAt || Date.now();
const processing_ms = Date.now() - startedAt;
const status = item.status || (item.intent === 'unknown' ? 'escalated' : 'sent');

const response_body = item.response_body || '';
const customer_name = item.customer_name || 'Customer';
const rag_sources = item.rag_sources || [];

let sourcesHtml = '';
if (rag_sources.length > 0) {
  sourcesHtml = '<p style="font-size:12px;color:#666;margin-top:16px;"><strong>Sources consulted:</strong> Knowledge base search</p>';
}

const response_html = `<!DOCTYPE html>
<html>
<body style="font-family: Arial, sans-serif; line-height: 1.6; color: #333;">
  <p>Hi ${customer_name},</p>
  <div>${response_body.replace(/\n/g, '<br>')}</div>
  ${sourcesHtml}
  <hr style="border: none; border-top: 1px solid #eee; margin: 24px 0;">
  <p style="font-size: 12px; color: #888;">AcmeCloud Support &bull; Intent: ${item.intent} &bull; Confidence: ${item.intent_confidence || 'n/a'} &bull; Ref: ${item.customer_email}</p>
</body>
</html>`;

return [{
  json: {
    ...item,
    response_html,
    processing_ms,
    status,
    email_subject: `Re: ${item.subject}`,
    rag_sources_json: JSON.stringify(rag_sources)
  }
}];

const email = $('Build Email').first().json;
