const gmailOk = !!(gmail.id || gmail.messageId || gmail.threadId);

return [{
  json: {
    ...email,
    gmail_message_id: gmail.id || gmail.messageId || '',
    status: gmailOk ? email.status : 'failed',
    error_message: gmailOk ? null : (gmail.errorMessage || gmail.message || 'Gmail send failed')
  }
}];
